        self._represented_shape_aspect_relationship = REPRESENTED_SHAPE_ASPECT_RELATIONSHIP
        self._representing_representation_relationship = REPRESENTING_REPRESENTATION_RELATIONSHIP

        super.init(asAbstractSuperclass:())
      }

      //PARTIAL ENTITY COPY CONSTRUCTOR
      /// copy constructor
      public required convenience init(from original:SDAI.PartialEntity) {
        let original = original as! Self
        self.init( REPRESENTED_SHAPE_ASPECT_RELATIONSHIP: original._represented_shape_aspect_relationship, REPRESENTING_REPRESENTATION_RELATIONSHIP: original._representing_representation_relationship )
      }

      //p21 PARTIAL ENTITY CONSTRUCTOR
      /// initialize from ISO 10303-21 exchange structure parameters
      public required convenience init?(
        parameters: [P21Decode.ExchangeStructure.Parameter],
        exchangeStructure: P21Decode.ExchangeStructure
      ) {
        let numParams = 2
        guard parameters.count == numParams
        else { exchangeStructure.error = "number of p21 parameters(\(parameters.count)) are different from expected(\(numParams)) for partial entity(\(Self.entityName)) constructor"; return nil }

        guard case .success(let p0) = exchangeStructure.recoverRequiredParameter(as: 
          eSHAPE_ASPECT_RELATIONSHIP.PRef.self, from: parameters[0])
        else { exchangeStructure.add(errorContext: "while recovering parameter [0]REPRESENTED_SHAPE_ASPECT_RELATIONSHIP for partial entity(\(Self.entityName)) constructor"); return nil }

        guard case .success(let p1) = exchangeStructure.recoverRequiredParameter(as: 
          eREPRESENTATION_RELATIONSHIP.PRef.self, from: parameters[1])
        else { exchangeStructure.add(errorContext: "while recovering parameter [1]REPRESENTING_REPRESENTATION_RELATIONSHIP for partial entity(\(Self.entityName)) constructor"); return nil }

        self.init( REPRESENTED_SHAPE_ASPECT_RELATIONSHIP: p0, REPRESENTING_REPRESENTATION_RELATIONSHIP: p1 )
      }
    }
  }
